LOG_FILE = os.path.join(os.environ["TEMP"], "yandex_music_installer.log")

def log(message):
    """Запись в лог-файл для отладки"""
    try:
        with open(LOG_FILE, "a", encoding="utf-8") as f:
            f.write(f"{time.strftime('%Y-%m-%d %H:%M:%S')} - {message}\n")
    except:
        pass

def create_shortcuts(target_path):
    """Создаёт ярлыки через PowerShell (Unicode-safe)"""
    try:
        desktop = os.path.join(os.environ["USERPROFILE"], "Desktop")
        start_menu = os.path.join(os.environ["APPDATA"], "Microsoft", "Windows", "Start Menu", "Programs")
        startup = os.path.join(start_menu, "Startup")
        working_dir = os.path.dirname(target_path)

        # Проверяем существование папок
        if not os.path.exists(desktop):
            log(f"Папка рабочего стола не найдена: {desktop}")
        if not os.path.exists(start_menu):
            log(f"Папка меню Пуск не найдена: {start_menu}")
        if not os.path.exists(startup):
            try:
                os.makedirs(startup)
                log(f"Создана папка автозагрузки: {startup}")
            except Exception as e:
                log(f"Не удалось создать папку автозагрузки: {e}")

        shortcut_paths = [
            os.path.join(desktop, "Yandex music mini.lnk"),
            os.path.join(start_menu, "Yandex music mini.lnk"),
            os.path.join(startup, "Yandex music mini.lnk")
        ]

        # Формируем PowerShell команды
        ps_commands = []
        for shortcut in shortcut_paths:
            # Экранируем одинарные кавычки
            shortcut_esc = shortcut.replace("'", "''")
            target_esc = target_path.replace("'", "''")
            workdir_esc = working_dir.replace("'", "''")
            ps_cmd = (
                f"$s = New-Object -ComObject WScript.Shell; "
                f"$link = $s.CreateShortcut('{shortcut_esc}'); "
                f"$link.TargetPath = '{target_esc}'; "
                f"$link.WorkingDirectory = '{workdir_esc}'; "
                f"$link.Save()"
            )
            ps_commands.append(ps_cmd)

        full_ps_command = "; ".join(ps_commands)
        # Кодируем команду в UTF-16LE и затем в Base64
        encoded_cmd = base64.b64encode(full_ps_command.encode('utf-16le')).decode('ascii')

        # Выполняем PowerShell
        result = subprocess.run(
            ["powershell.exe", "-NoProfile", "-ExecutionPolicy", "Bypass", "-EncodedCommand", encoded_cmd],
            capture_output=True, text=True
        )
        if result.returncode != 0:
            log(f"Ошибка PowerShell: {result.stderr}")
        else:
            log("Ярлыки успешно созданы через PowerShell")

    except Exception as e:
        log(f"Ошибка в create_shortcuts: {e}")
def remove_shortcuts():
    """Удаляет все ярлыки приложения"""
    try:
        desktop = os.path.join(os.environ["USERPROFILE"], "Desktop")
        start_menu = os.path.join(os.environ["APPDATA"], "Microsoft", "Windows", "Start Menu", "Programs")
        startup = os.path.join(start_menu, "Startup")

        for folder in [desktop, start_menu, startup]:
            shortcut = os.path.join(folder, "Яндекс Музыка.lnk")
            if os.path.exists(shortcut):
                os.remove(shortcut)
                log(f"Удалён ярлык: {shortcut}")
    except Exception as e:
        log(f"Ошибка удаления ярлыков: {e}")

def remove_vlc_shortcuts():
    """Удаляет ярлыки VLC с рабочего стола и из меню Пуск"""
    try:
        desktop = os.path.join(os.environ["USERPROFILE"], "Desktop")
        start_menu = os.path.join(os.environ["APPDATA"], "Microsoft", "Windows", "Start Menu", "Programs")

        # Возможные имена ярлыков VLC
        vlc_names = ["VLC media player.lnk", "VLC.lnk", "VideoLAN.lnk"]
        vlc_folder = os.path.join(start_menu, "VideoLAN")

        # Удаляем ярлыки на рабочем столе
        for name in vlc_names:
            path = os.path.join(desktop, name)
            if os.path.exists(path):
                os.remove(path)
                log(f"Удалён ярлык VLC: {path}")

        # Удаляем папку VideoLAN в меню Пуск
        if os.path.exists(vlc_folder):
            shutil.rmtree(vlc_folder)
            log(f"Удалена папка VideoLAN из меню Пуск: {vlc_folder}")
    except Exception as e:
        log(f"Ошибка удаления ярлыков VLC: {e}")

def is_vlc_installed():
    for hkey in [winreg.HKEY_LOCAL_MACHINE, winreg.HKEY_CURRENT_USER]:
        for subkey in [r"SOFTWARE\VideoLAN\VLC", r"SOFTWARE\WOW6432Node\VideoLAN\VLC"]:
            try:
                with winreg.OpenKey(hkey, subkey) as key:
                    return True
            except:
                continue
    return False

def remove_config():
    try:
        if os.path.exists(CONFIG_FILE):
            os.remove(CONFIG_FILE)
            log("Конфиг удалён")
    except Exception as e:
        log(f"Ошибка удаления конфига: {e}")

def remove_autostart_registry():
    try:
        key_path = r"Software\Microsoft\Windows\CurrentVersion\Run"
        with winreg.OpenKey(winreg.HKEY_CURRENT_USER, key_path, 0, winreg.KEY_SET_VALUE) as key:
            try:
                winreg.DeleteValue(key, "Яндекс.Музыка мини")
                log("Запись автозагрузки удалена из реестра")
            except FileNotFoundError:
                pass
    except Exception as e:
        log(f"Ошибка удаления из реестра: {e}")

class InstallerApp:
    def __init__(self, root):
        self.root = root
        self.root.title(APP_NAME)
        self.root.configure(bg=BG_COLOR)

        w, h = 420, 180
        x = (self.root.winfo_screenwidth() // 2) - (w // 2)
        y = (self.root.winfo_screenheight() // 2) - (h // 2)
        self.root.geometry(f'{w}x{h}+{x}+{y}')
        self.root.resizable(False, False)

        # Стили для кнопок (ещё более минималистичные)
        self.style = ttk.Style()
        self.style.theme_use("clam")

        self.style.configure("Modern.TButton",
                             font=("Segoe UI Variable", 9, "normal"),
                             padding=(16, 8),
                             background="#f5f5f5",
                             foreground="#222222",
                             borderwidth=0,
                             focuscolor="none",
                             relief="flat")
        self.style.map("Modern.TButton",
                       background=[('active', '#e0e0e0'), ('pressed', '#d0d0d0')])

        self.style.configure("Flat.Horizontal.TProgressbar",
                             troughcolor=PROGRESS_BG,
                             background=PROGRESS_FILL,
                             bordercolor=PROGRESS_BG,
                             lightcolor=PROGRESS_FILL,
                             darkcolor=PROGRESS_FILL,
                             borderwidth=0,
                             thickness=12)
        self.style.layout("Flat.Horizontal.TProgressbar",
                          [('Horizontal.Progressbar.trough',
                            {'children': [('Horizontal.Progressbar.pbar', {'side': 'left', 'sticky': 'nswe'})],
                             'sticky': 'nswe'})])

        # Иконка (если есть)
        self.icon_img = None
        if 'ICON_BASE64' in globals():
            try:
                img_data = base64.b64decode(ICON_BASE64)
                pil_img = Image.open(io.BytesIO(img_data)).convert("RGBA").resize((48, 48))
                self.icon_img = ImageTk.PhotoImage(pil_img)
                self.root.iconphoto(True, self.icon_img)
            except Exception as e:
                log(f"Ошибка загрузки иконки: {e}")

        self.container = tk.Frame(self.root, bg=BG_COLOR)
        self.container.pack(fill="both", expand=True, padx=25, pady=20)

        self.header = tk.Frame(self.container, bg=BG_COLOR)
        self.header.pack(fill="x", anchor="nw")

        if self.icon_img:
            tk.Label(self.header, image=self.icon_img, bg=BG_COLOR).pack(side="left")

        self.status_label = tk.Label(self.header, text="Подготовка...", font=("Segoe UI Variable", 9), bg=BG_COLOR,
                                     fg=TEXT_COLOR)
        self.status_label.pack(side="left", padx=15, pady=(0, 15))

        self.progress = ttk.Progressbar(self.container, style="Flat.Horizontal.TProgressbar", orient="horizontal",
                                        mode="determinate")

        self.btn_frame = tk.Frame(self.container, bg=BG_COLOR)

        self.check_existing_install()

    def check_existing_install(self):
        app_exe = os.path.join(INSTALL_DIR, EXE_NAME)
        if os.path.exists(app_exe):
            self.status_label.config(text="Программа уже установлена")
            self.progress.pack_forget()
            self.btn_frame.pack(side="bottom", pady=5)
            ttk.Button(self.btn_frame, text="ОБНОВИТЬ", style="Modern.TButton",
                       command=self.start_installation).pack(side="left", padx=5)
            ttk.Button(self.btn_frame, text="УДАЛИТЬ", style="Modern.TButton",
                       command=self.uninstall_app).pack(side="left", padx=5)
            ttk.Button(self.btn_frame, text="ПОЧИНИТЬ", style="Modern.TButton",
                       command=self.repair_app).pack(side="left", padx=5)
        else:
            self.start_installation()

    def start_installation(self):
        self.btn_frame.pack_forget()
        self.progress.pack(side="bottom", fill="x", pady=(5, 0))
        threading.Thread(target=self.run_logic, daemon=True).start()

    def run_logic(self, clean_install=False):
        try:
            # 1. Проверка/установка VLC
            if not is_vlc_installed():
                vlc_path = os.path.join(os.environ["TEMP"], "vlc_setup.exe")
                self.update_ui("Загрузка системных компонентов...", 0)
                if self.download_with_progress(VLC_DOWNLOAD_URL, vlc_path):
                    self.update_ui("Установка системных компонентов...", 70)
                    # /S - тихая установка, /no-shortcuts - без ярлыков
                    subprocess.run([vlc_path, "/S", "/no-shortcuts"], check=False)
                    # На всякий случай удаляем возможные ярлыки VLC
                    remove_vlc_shortcuts()

            # 2. Загрузка и установка приложения
            self.update_ui("Загрузка Яндекс Музыки мини...", 30)
            os.makedirs(INSTALL_DIR, exist_ok=True)
            app_exe = os.path.join(INSTALL_DIR, EXE_NAME)

            if self.download_with_progress(APP_DOWNLOAD_URL, app_exe):
                self.update_ui("Создание ярлыков...", 90)
                create_shortcuts(app_exe)
                self.update_ui("Установка завершена!", 100)
                time.sleep(2)
                self.root.destroy()
        except Exception as e:
            log(f"Ошибка установки: {e}")
            self.update_ui("Ошибка установки", 0)
            messagebox.showerror("Ошибка", f"Произошла ошибка:\n{e}")

    def download_with_progress(self, url, dest):
        try:
            response = requests.get(url, stream=True, timeout=20)
            response.raise_for_status()
            total = int(response.headers.get('content-length', 0))
            dl = 0
            with open(dest, 'wb') as f:
                for chunk in response.iter_content(chunk_size=8192):
                    if chunk:
                        f.write(chunk)
                        dl += len(chunk)
                        if total > 0:
                            percent = (dl / total) * 100
                            self.root.after(0, self.progress.configure, {"value": percent})
            log(f"Скачан файл: {dest}")
            return True
        except Exception as e:
            log(f"Ошибка скачивания {url}: {e}")
            return False

    def uninstall_app(self):
        if messagebox.askyesno("Удаление", "Вы уверены, что хотите полностью удалить программу и все её компоненты?"):
            try:
                # Удаляем папку с программой
                if os.path.exists(INSTALL_DIR):
                    shutil.rmtree(INSTALL_DIR)
                    log("Папка программы удалена")

                remove_config()
                remove_shortcuts()
                remove_autostart_registry()

                # По желанию можно удалить и ярлыки VLC, но сам VLC не трогаем
                # remove_vlc_shortcuts()

                messagebox.showinfo("Готово", "Программа и все связанные файлы удалены")
                self.root.destroy()
            except Exception as e:
                log(f"Ошибка удаления: {e}")
                messagebox.showerror("Ошибка", f"Не удалось полностью удалить:\n{e}")

    def repair_app(self):
        if messagebox.askyesno("Восстановление",
                               "Это удалит текущую установку и ярлыки, затем переустановит приложение. Продолжить?"):
            try:
                if os.path.exists(INSTALL_DIR):
                    shutil.rmtree(INSTALL_DIR)
                remove_config()
                remove_shortcuts()
                remove_autostart_registry()
                self.start_installation()
            except Exception as e:
                log(f"Ошибка восстановления: {e}")
                messagebox.showerror("Ошибка", f"Не удалось выполнить восстановление:\n{e}")

    def update_ui(self, text, val):
        self.status_label.config(text=text)
        self.progress["value"] = val
        self.root.update_idletasks()

if __name__ == "__main__":
    # Очистка старого лога
    try:
        if os.path.exists(LOG_FILE):
            os.remove(LOG_FILE)
    except:
        pass
    log("Запуск установщика")
    root = tk.Tk()
    app = InstallerApp(root)
    root.mainloop()